// mockTransformer is a mock implementation of the Transformer interface for testing.
type mockTransformer struct {
	encryptedData []byte
	decryptedData []byte
	encryptErr    error
	decryptErr    error
	staleFlag     bool
	receivedData  []byte
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.receivedData = make([]byte, len(data))
	copy(m.receivedData, data)
	if m.decryptErr != nil {
		return nil, false, m.decryptErr
	}
	return m.decryptedData, m.staleFlag, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.receivedData = make([]byte, len(data))
	copy(m.receivedData, data)
	if m.encryptErr != nil {
		return nil, m.encryptErr
	}
	return m.encryptedData, nil
}

// TestDefaultContextAuthenticatedData tests the DefaultContext implementation.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		input    []byte
		expected []byte
	}{
		{
			name:     "empty data",
			input:    []byte{},
			expected: []byte{},
		},
		{
			name:     "simple bytes",
			input:    []byte("test"),
			expected: []byte("test"),
		},
		{
			name:     "complex bytes",
			input:    []byte{0x00, 0x01, 0x02, 0xFF},
			expected: []byte{0x00, 0x01, 0x02, 0xFF},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.input)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("AuthenticatedData() = %v, want %v", result, tc.expected)
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt/decrypt round-trips.
func TestTransformerRoundTrip(t *testing.T) {
	// Create a mock transformer that simulates encryption
	encrypted := []byte("encrypted_data")
	decrypted := []byte("original_data")

	transformer := &mockTransformer{
		encryptedData: encrypted,
		decryptedData: decrypted,
	}

	ctx := context.Background()

	// Test ToStorage
	result, err := transformer.TransformToStorage(ctx, decrypted, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if !bytes.Equal(result, encrypted) {
		t.Errorf("TransformToStorage() = %v, want %v", result, encrypted)
	}

	// Test FromStorage
	result, stale, err := transformer.TransformFromStorage(ctx, encrypted, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(result, decrypted) {
		t.Errorf("TransformFromStorage() = %v, want %v", result, decrypted)
	}
	if stale {
		t.Errorf("TransformFromStorage() stale = true, want false")
	}
}

// TestTransformerRoundTripTableDriven tests round-trip transformations with table-driven tests.
func TestTransformerRoundTripTableDriven(t *testing.T) {
	testCases := []struct {
		name           string
		originalData   []byte
		encryptedData  []byte
		encryptErr     error
		decryptErr     error
		stale          bool
		shouldFail     bool
		failureMessage string
	}{
		{
			name:          "simple encryption",
			originalData:  []byte("hello"),
			encryptedData: []byte("enc_hello"),
			shouldFail:    false,
		},
		{
			name:           "empty data",
			originalData:   []byte{},
			encryptedData:  []byte{},
			shouldFail:     false,
		},
		{
			name:           "encryption error",
			originalData:   []byte("data"),
			encryptErr:     fmt.Errorf("encryption failed"),
			shouldFail:     true,
			failureMessage: "encryption failed",
		},
		{
			name:           "decryption error",
			originalData:   []byte("data"),
			encryptedData:  []byte("encrypted"),
			decryptErr:     fmt.Errorf("decryption failed"),
			shouldFail:     true,
			failureMessage: "decryption failed",
		},
		{
			name:          "large data",
			originalData:  bytes.Repeat([]byte("x"), 10000),
			encryptedData: bytes.Repeat([]byte("y"), 10000),
			shouldFail:    false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptedData: tc.encryptedData,
				decryptedData: tc.originalData,
				encryptErr:    tc.encryptErr,
				decryptErr:    tc.decryptErr,
				staleFlag:     tc.stale,
			}

			ctx := context.Background()

			// Test encryption
			result, err := transformer.TransformToStorage(ctx, tc.originalData, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Fatalf("TransformToStorage() expected error %q, got nil", tc.failureMessage)
				}
				if err.Error() != tc.failureMessage {
					t.Errorf("TransformToStorage() error = %v, want %v", err, tc.encryptErr)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.encryptedData) {
				t.Errorf("TransformToStorage() = %v, want %v", result, tc.encryptedData)
			}

			// Test decryption
			result, stale, err := transformer.TransformFromStorage(ctx, tc.encryptedData, nil)
			if tc.decryptErr != nil {
				if err == nil {
					t.Fatalf("TransformFromStorage() expected error %q, got nil", tc.failureMessage)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.originalData) {
				t.Errorf("TransformFromStorage() = %v, want %v", result, tc.originalData)
			}
			if stale != tc.stale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.stale)
			}
		})
	}
}

// TestPrefixTransformerPrefixMatching tests that PrefixTransformer correctly matches prefixes.
func TestPrefixTransformerPrefixMatching(t *testing.T) {
	testCases := []struct {
		name            string
		prefix          []byte
		data            []byte
		shouldMatch     bool
		expectedOutput  []byte
		expectedError   string
	}{
		{
			name:           "matching prefix",
			prefix:         []byte("prefix:"),
			data:           []byte("prefix:data"),
			shouldMatch:    true,
			expectedOutput: []byte("transformed"),
		},
		{
			name:          "non-matching prefix",
			prefix:        []byte("prefix:"),
			data:          []byte("other:data"),
			shouldMatch:   false,
			expectedError: "no matching prefix",
		},
		{
			name:           "exact prefix match",
			prefix:         []byte("k8s:enc:aescbc:v1:"),
			data:           []byte("k8s:enc:aescbc:v1:encrypted_payload"),
			shouldMatch:    true,
			expectedOutput: []byte("decrypted"),
		},
		{
			name:           "empty prefix",
			prefix:         []byte{},
			data:           []byte("anydata"),
			shouldMatch:    true,
			expectedOutput: []byte("result"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mockTrans := &mockTransformer{
				decryptedData: tc.expectedOutput,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: mockTrans,
				},
			)

			ctx := context.Background()
			result, _, err := transformer.TransformFromStorage(ctx, tc.data, nil)

			if tc.shouldMatch {
				if err != nil {
					t.Fatalf("TransformFromStorage() unexpected error: %v", err)
				}
				if !bytes.Equal(result, tc.expectedOutput) {
					t.Errorf("TransformFromStorage() = %v, want %v", result, tc.expectedOutput)
				}
			} else {
				if err == nil {
					t.Fatalf("TransformFromStorage() expected error, got nil")
				}
				if err.Error() != tc.expectedError {
					t.Errorf("TransformFromStorage() error = %v, want error containing %q", err, tc.expectedError)
				}
			}
		})
	}
}

// TestPrefixTransformerStaleMarking tests that non-first transformers are marked as stale.
func TestPrefixTransformerStaleMarking(t *testing.T) {
	testCases := []struct {
		name          string
		matchIndex    int
		expectedStale bool
	}{
		{
			name:          "first transformer not stale",
			matchIndex:    0,
			expectedStale: false,
		},
		{
			name:          "second transformer is stale",
			matchIndex:    1,
			expectedStale: true,
		},
		{
			name:          "third transformer is stale",
			matchIndex:    2,
			expectedStale: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Create multiple transformers with different prefixes
			transformers := []PrefixTransformer{
				{
					Prefix: []byte("first:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data1"),
					},
				},
				{
					Prefix: []byte("second:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data2"),
					},
				},
				{
					Prefix: []byte("third:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data3"),
					},
				},
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no match"),
				transformers...,
			)

			ctx := context.Background()
			data := append(transformers[tc.matchIndex].Prefix, []byte("payload")...)

			_, stale, err := transformer.TransformFromStorage(ctx, data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if stale != tc.expectedStale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.expectedStale)
			}
		})
	}
}

// TestPrefixTransformerToStorageUsesFirst tests that TransformToStorage uses the first transformer.
func TestPrefixTransformerToStorageUsesFirst(t *testing.T) {
	ctx := context.Background()

	mockFirst := &mockTransformer{
		encryptedData: []byte("encrypted_by_first"),
	}
	mockSecond := &mockTransformer{
		encryptedData: []byte("encrypted_by_second"),
	}

	transformers := []PrefixTransformer{
		{
			Prefix:      []byte("first:"),
			Transformer: mockFirst,
		},
		{
			Prefix:      []byte("second:"),
			Transformer: mockSecond,
		},
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		transformers...,
	)

	result, err := transformer.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	expected := append([]byte("first:"), []byte("encrypted_by_first")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage() = %v, want %v", result, expected)
	}

	// Verify that only the first transformer was called
	if !bytes.Equal(mockFirst.receivedData, []byte("data")) {
		t.Errorf("First transformer received %v, want %v", mockFirst.receivedData, []byte("data"))
	}
}

// TestPrefixTransformerErrorPropagation tests error handling.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	testCases := []struct {
		name        string
		transformers []PrefixTransformer
		data        []byte
		expectError bool
	}{
		{
			name: "encryption error",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						encryptErr: fmt.Errorf("encryption failed"),
					},
				},
			},
			data:        []byte("plaintext"),
			expectError: true,
		},
		{
			name: "decryption error for matching prefix",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("dec:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("decryption failed"),
					},
				},
			},
			data:        []byte("dec:ciphertext"),
			expectError: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := NewPrefixTransformers(
				fmt.Errorf("default error"),
				tc.transformers...,
			)

			ctx := context.Background()

			if len(tc.transformers[0].Transformer.(*mockTransformer).encryptedData) > 0 {
				// Test ToStorage
				_, err := transformer.TransformToStorage(ctx, tc.data, nil)
				if (err != nil) != tc.expectError {
					t.Errorf("TransformToStorage() error = %v, expectError = %v", err, tc.expectError)
				}
			}

			// Test FromStorage
			_, _, err := transformer.TransformFromStorage(ctx, tc.data, nil)
			if (err != nil) != tc.expectError {
				t.Errorf("TransformFromStorage() error = %v, expectError = %v", err, tc.expectError)
			}
		})
	}
}

// TestPrefixTransformerEmptyValue tests handling of empty values.
func TestPrefixTransformerEmptyValue(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		inputData      []byte
		expectedOutput []byte
		shouldFail     bool
	}{
		{
			name:           "empty data with prefix",
			prefix:         []byte("prefix:"),
			inputData:      []byte("prefix:"),
			expectedOutput: []byte("transformed"),
			shouldFail:     false,
		},
		{
			name:       "completely empty data",
			prefix:     []byte("prefix:"),
			inputData:  []byte{},
			shouldFail: true,
		},
		{
			name:           "only payload is empty",
			prefix:         []byte("k8s:"),
			inputData:      []byte("k8s:"),
			expectedOutput: []byte{},
			shouldFail:     false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mockTrans := &mockTransformer{
				decryptedData: tc.expectedOutput,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: mockTrans,
				},
			)

			ctx := context.Background()
			_, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if tc.shouldFail && err == nil {
				t.Fatalf("TransformFromStorage() expected error, got nil")
			}
			if !tc.shouldFail && err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
		})
	}
}

// TestPrefixTransformerNoMatchingPrefix tests default error when no prefix matches.
func TestPrefixTransformerNoMatchingPrefix(t *testing.T) {
	customErr := fmt.Errorf("custom no-match error")

	transformer := NewPrefixTransformers(
		customErr,
		PrefixTransformer{
			Prefix: []byte("known:"),
			Transformer: &mockTransformer{
				decryptedData: []byte("result"),
			},
		},
	)

	ctx := context.Background()
	_, _, err := transformer.TransformFromStorage(ctx, []byte("unknown:data"), nil)

	if err != customErr {
		t.Errorf("TransformFromStorage() error = %v, want %v", err, customErr)
	}
}

// TestPrefixTransformerDefaultError tests that a default error is created if nil is provided.
func TestPrefixTransformerDefaultError(t *testing.T) {
	transformer := NewPrefixTransformers(
		nil, // nil error should create a default one
		PrefixTransformer{
			Prefix: []byte("prefix:"),
			Transformer: &mockTransformer{
				decryptedData: []byte("result"),
			},
		},
	)

	ctx := context.Background()
	_, _, err := transformer.TransformFromStorage(ctx, []byte("other:data"), nil)

	if err == nil {
		t.Fatalf("TransformFromStorage() expected error, got nil")
	}
	// Should contain the default error message
	if err.Error() != "the provided value does not match any of the supported transformers" {
		t.Errorf("TransformFromStorage() error message = %q, want 'the provided value does not match any of the supported transformers'", err.Error())
	}
}

// TestPrefixTransformerContextPropagation tests that context is propagated to transformers.
func TestPrefixTransformerContextPropagation(t *testing.T) {
	type contextKey string
	const testKey contextKey = "testkey"

	mockTrans := &mockTransformer{
		encryptedData: []byte("encrypted"),
		decryptedData: []byte("decrypted"),
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("pre:"),
			Transformer: mockTrans,
		},
	)

	ctx := context.WithValue(context.Background(), testKey, "testvalue")

	// Test ToStorage with context
	_, err := transformer.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	// Test FromStorage with context
	_, _, err = transformer.TransformFromStorage(ctx, []byte("pre:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
}

