// mockTransformer is a mock implementation of the Transformer interface for testing.
type mockTransformer struct {
	encryptedData []byte
	decryptedData []byte
	encryptErr    error
	decryptErr    error
	staleFlag     bool
	receivedData  []byte
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.receivedData = make([]byte, len(data))
	copy(m.receivedData, data)
	if m.decryptErr != nil {
		return nil, false, m.decryptErr
	}
	return m.decryptedData, m.staleFlag, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.receivedData = make([]byte, len(data))
	copy(m.receivedData, data)
	if m.encryptErr != nil {
		return nil, m.encryptErr
	}
	return m.encryptedData, nil
}

