		stale          bool
		shouldFail     bool
		failureMessage string
	}{
		{
			name:          "simple encryption",
			originalData:  []byte("hello"),
			encryptedData: []byte("enc_hello"),
			shouldFail:    false,
		},
		{
			name:           "empty data",
			originalData:   []byte{},
			encryptedData:  []byte{},
			shouldFail:     false,
		},
		{
			name:           "encryption error",
			originalData:   []byte("data"),
			encryptErr:     fmt.Errorf("encryption failed"),
			shouldFail:     true,
			failureMessage: "encryption failed",
		},
		{
			name:           "decryption error",
			originalData:   []byte("data"),
			encryptedData:  []byte("encrypted"),
			decryptErr:     fmt.Errorf("decryption failed"),
			shouldFail:     true,
			failureMessage: "decryption failed",
		},
		{
			name:          "large data",
			originalData:  bytes.Repeat([]byte("x"), 10000),
			encryptedData: bytes.Repeat([]byte("y"), 10000),
			shouldFail:    false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptedData: tc.encryptedData,
				decryptedData: tc.originalData,
				encryptErr:    tc.encryptErr,
				decryptErr:    tc.decryptErr,
				staleFlag:     tc.stale,
			}

			ctx := context.Background()

			// Test encryption
			result, err := transformer.TransformToStorage(ctx, tc.originalData, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Fatalf("TransformToStorage() expected error %q, got nil", tc.failureMessage)
				}
				if err.Error() != tc.failureMessage {
					t.Errorf("TransformToStorage() error = %v, want %v", err, tc.encryptErr)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.encryptedData) {
				t.Errorf("TransformToStorage() = %v, want %v", result, tc.encryptedData)
			}

			// Test decryption
			result, stale, err := transformer.TransformFromStorage(ctx, tc.encryptedData, nil)
			if tc.decryptErr != nil {
				if err == nil {
					t.Fatalf("TransformFromStorage() expected error %q, got nil", tc.failureMessage)
				}
				return
			}
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(result, tc.originalData) {
				t.Errorf("TransformFromStorage() = %v, want %v", result, tc.originalData)
			}
			if stale != tc.stale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.stale)
			}
		})
	}
}

// TestPrefixTransformerPrefixMatching tests that PrefixTransformer correctly matches prefixes.
func TestPrefixTransformerPrefixMatching(t *testing.T) {
	testCases := []struct {
		name            string
		prefix          []byte
		data            []byte
		shouldMatch     bool
		expectedOutput  []byte
		expectedError   string
	}{
		{
			name:           "matching prefix",
			prefix:         []byte("prefix:"),
			data:           []byte("prefix:data"),
			shouldMatch:    true,
			expectedOutput: []byte("transformed"),
		},
		{
			name:          "non-matching prefix",
			prefix:        []byte("prefix:"),
			data:          []byte("other:data"),
			shouldMatch:   false,
			expectedError: "no matching prefix",
		},
		{
			name:           "exact prefix match",
			prefix:         []byte("k8s:enc:aescbc:v1:"),
			data:           []byte("k8s:enc:aescbc:v1:encrypted_payload"),
			shouldMatch:    true,
			expectedOutput: []byte("decrypted"),
		},
		{
			name:           "empty prefix",
			prefix:         []byte{},
			data:           []byte("anydata"),
			shouldMatch:    true,
			expectedOutput: []byte("result"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mockTrans := &mockTransformer{
				decryptedData: tc.expectedOutput,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: mockTrans,
				},
			)

			ctx := context.Background()
			result, _, err := transformer.TransformFromStorage(ctx, tc.data, nil)

			if tc.shouldMatch {
				if err != nil {
					t.Fatalf("TransformFromStorage() unexpected error: %v", err)
				}
				if !bytes.Equal(result, tc.expectedOutput) {
					t.Errorf("TransformFromStorage() = %v, want %v", result, tc.expectedOutput)
				}
			} else {
				if err == nil {
					t.Fatalf("TransformFromStorage() expected error, got nil")
				}
				if err.Error() != tc.expectedError {
					t.Errorf("TransformFromStorage() error = %v, want error containing %q", err, tc.expectedError)
				}
			}
		})
	}
}

// TestPrefixTransformerStaleMarking tests that non-first transformers are marked as stale.
func TestPrefixTransformerStaleMarking(t *testing.T) {
	testCases := []struct {
		name          string
		matchIndex    int
		expectedStale bool
	}{
		{
			name:          "first transformer not stale",
			matchIndex:    0,
			expectedStale: false,
		},
		{
			name:          "second transformer is stale",
			matchIndex:    1,
			expectedStale: true,
		},
		{
			name:          "third transformer is stale",
			matchIndex:    2,
			expectedStale: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Create multiple transformers with different prefixes
			transformers := []PrefixTransformer{
				{
					Prefix: []byte("first:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data1"),
					},
				},
				{
					Prefix: []byte("second:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data2"),
					},
				},
				{
					Prefix: []byte("third:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("data3"),
					},
				},
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no match"),
				transformers...,
			)

			ctx := context.Background()
			data := append(transformers[tc.matchIndex].Prefix, []byte("payload")...)

			_, stale, err := transformer.TransformFromStorage(ctx, data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if stale != tc.expectedStale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.expectedStale)
			}
