}

// TestPrefixTransformerToStorageUsesFirst tests that TransformToStorage uses the first transformer.
func TestPrefixTransformerToStorageUsesFirst(t *testing.T) {
	ctx := context.Background()

	mockFirst := &mockTransformer{
		encryptedData: []byte("encrypted_by_first"),
	}
	mockSecond := &mockTransformer{
		encryptedData: []byte("encrypted_by_second"),
	}

	transformers := []PrefixTransformer{
		{
			Prefix:      []byte("first:"),
			Transformer: mockFirst,
		},
		{
			Prefix:      []byte("second:"),
			Transformer: mockSecond,
		},
	}

	transformer := NewPrefixTransformers(
		fmt.Errorf("no match"),
		transformers...,
	)

	result, err := transformer.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	expected := append([]byte("first:"), []byte("encrypted_by_first")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage() = %v, want %v", result, expected)
	}

	// Verify that only the first transformer was called
	if !bytes.Equal(mockFirst.receivedData, []byte("data")) {
		t.Errorf("First transformer received %v, want %v", mockFirst.receivedData, []byte("data"))
	}
}

