			inputData:      []byte("prefix:"),
			expectedOutput: []byte("transformed"),
			shouldFail:     false,
		},
		{
			name:       "completely empty data",
			prefix:     []byte("prefix:"),
			inputData:  []byte{},
			shouldFail: true,
		},
		{
			name:           "only payload is empty",
			prefix:         []byte("k8s:"),
			inputData:      []byte("k8s:"),
			expectedOutput: []byte{},
			shouldFail:     false,
		},
	}

	for _, tc := range testCases {
