		transformers []PrefixTransformer
		data        []byte
		expectError bool
	}{
		{
			name: "encryption error",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						encryptErr: fmt.Errorf("encryption failed"),
					},
				},
			},
			data:        []byte("plaintext"),
			expectError: true,
		},
		{
			name: "decryption error for matching prefix",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("dec:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("decryption failed"),
					},
				},
			},
			data:        []byte("dec:ciphertext"),
			expectError: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := NewPrefixTransformers(
				fmt.Errorf("default error"),
				tc.transformers...,
			)

			ctx := context.Background()

			if len(tc.transformers[0].Transformer.(*mockTransformer).encryptedData) > 0 {
				// Test ToStorage
				_, err := transformer.TransformToStorage(ctx, tc.data, nil)
				if (err != nil) != tc.expectError {
					t.Errorf("TransformToStorage() error = %v, expectError = %v", err, tc.expectError)
				}
			}

			// Test FromStorage
			_, _, err := transformer.TransformFromStorage(ctx, tc.data, nil)
			if (err != nil) != tc.expectError {
				t.Errorf("TransformFromStorage() error = %v, expectError = %v", err, tc.expectError)
			}
		})
	}
}

// TestPrefixTransformerEmptyValue tests handling of empty values.
func TestPrefixTransformerEmptyValue(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		inputData      []byte
		expectedOutput []byte
		shouldFail     bool
	}{
		{
			name:           "empty data with prefix",
			prefix:         []byte("prefix:"),
			inputData:      []byte("prefix:"),
			expectedOutput: []byte("transformed"),
			shouldFail:     false,
		},
		{
			name:       "completely empty data",
			prefix:     []byte("prefix:"),
			inputData:  []byte{},
			shouldFail: true,
		},
		{
			name:           "only payload is empty",
			prefix:         []byte("k8s:"),
			inputData:      []byte("k8s:"),
			expectedOutput: []byte{},
			shouldFail:     false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			mockTrans := &mockTransformer{
				decryptedData: tc.expectedOutput,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: mockTrans,
				},
			)

			ctx := context.Background()
			_, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if tc.shouldFail && err == nil {
				t.Fatalf("TransformFromStorage() expected error, got nil")
			}
			if !tc.shouldFail && err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
		})
	}
}

